func formatDealValue(cents int64, currency string) string {
	symbol := dealCurrencySymbol(currency)
	val := float64(cents) / 100.0
	return fmt.Sprintf("%s%.2f", symbol, val)
}

func formatDealValueRaw(cents int64) string {
	val := float64(cents) / 100.0
	return fmt.Sprintf("%.2f", val)
}

func dealCurrencySymbol(currency string) string {
	switch currency {
	case "EUR":
		return "\u20ac"
	case "USD":
		return "$"
	case "GBP":
		return "\u00a3"
	default:
		return currency + " "
	}
}

